queries.sparql:
PREFIX : <http://ambrosia.example.org/education#>
PREFIX p: <http://ambrosia.example.org/education/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?chapter_name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasChapters ?child ; p:hasTextbooks ?parent . } GROUP BY ?child }
  ?child p:chapter_name ?chapter_name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Textbooks } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/education#>
PREFIX p: <http://ambrosia.example.org/education/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  distributive: { SELECT ?title ?chapter_name WHERE {
  ?textbook_chapters a :Textbook_Chapters .
  ?chapters a :Chapters .
  ?textbook_chapters p:hasChapters ?chapters .
  ?textbooks a :Textbooks .
  ?textbook_chapters p:hasTextbooks ?textbooks .
  ?textbooks p:title ?title .
  ?chapters p:chapter_name ?chapter_name .
} }
  collective: { SELECT ?chapter_name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasChapters ?child ; p:hasTextbooks ?parent . } GROUP BY ?child }
  ?child p:chapter_name ?chapter_name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Textbooks } }
  FILTER(?nf = ?total)
} }
}
